#include <bits/stdc++.h>
using namespace std;

struct Node{
    int to,val;
};

bool operator<(Node x,Node y){
    return x.val>y.val;
}

int n,m,k,s,t,dist[110004];
bool init[110004];
vector<Node> g[110004];

void Dijkstra(){
    priority_queue<Node> q;
    memset(dist,0x3f,sizeof(dist));
    dist[s]=0;
    q.push({s,0});
    while(q.size()){
        while(q.size() && init[q.top().to])
            q.pop();
        if(!q.size())
        	break;
        int x=q.top().to,len=g[x].size();
        q.pop(),init[x]=1;
        for(int i=0;i<len;i++)
            if(!init[g[x][i].to] && dist[g[x][i].to]>dist[x]+g[x][i].val)
                dist[g[x][i].to]=dist[x]+g[x][i].val,q.push({g[x][i].to,dist[g[x][i].to]});
    }
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    scanf("%d%d",&s,&t);
    for(int i=1;i<=m;i++){
        int a,b,c;
        scanf("%d%d%d",&a,&b,&c);
        for(int i=0;i<=k;i++){
            g[i*n+a].push_back({i*n+b,c});
            g[i*n+b].push_back({i*n+a,c});
            if(i<k){
                g[i*n+a].push_back({(i+1)*n+b,0});
                g[i*n+b].push_back({(i+1)*n+a,0});
            }
        }
    }

    Dijkstra();
    int ans=2e9;
    for(int i=0;i<=k;i++)
        ans=min(ans,dist[t+i*n]);
    printf("%d",ans);
    return 0;
}
